// TestMultiplePrefixTransformers verifies correct transformer selection and write behavior
func TestMultiplePrefixTransformers(t *testing.T) {
	transformer1 := &mockTransformer{
		decryptedData: []byte("result1"),
		encryptedData: []byte("encrypted1"),
	}
	transformer2 := &mockTransformer{
		decryptedData: []byte("result2"),
		encryptedData: []byte("encrypted2"),
	}
	transformer3 := &mockTransformer{
		decryptedData: []byte("result3"),
		encryptedData: []byte("encrypted3"),
	}

	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("aes:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("kms:"), Transformer: transformer2},
		PrefixTransformer{Prefix: []byte("legacy:"), Transformer: transformer3},
	)

	ctx := context.Background()

	tests := []struct {
		name                 string
		data                 []byte
		expectTransformer    *mockTransformer
		expectResult         []byte
		expectReceivedData   []byte
	}{
		{
			name:                 "first prefix matches",
			data:                 []byte("aes:encrypted1"),
			expectTransformer:    transformer1,
			expectResult:         []byte("result1"),
			expectReceivedData:   []byte("encrypted1"),
		},
		{
			name:                 "second prefix matches",
			data:                 []byte("kms:encrypted2"),
			expectTransformer:    transformer2,
			expectResult:         []byte("result2"),
			expectReceivedData:   []byte("encrypted2"),
		},
		{
			name:                 "third prefix matches",
			data:                 []byte("legacy:encrypted3"),
			expectTransformer:    transformer3,
			expectResult:         []byte("result3"),
			expectReceivedData:   []byte("encrypted3"),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result, _, err := p.TransformFromStorage(ctx, tt.data, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if !bytes.Equal(result, tt.expectResult) {
				t.Errorf("TransformFromStorage returned %q, want %q", result, tt.expectResult)
			}

			if !bytes.Equal(tt.expectTransformer.receivedFromStorage, tt.expectReceivedData) {
				t.Errorf("transformer received %q, want %q", tt.expectTransformer.receivedFromStorage, tt.expectReceivedData)
			}
		})
	}

	// Test that write always uses the first transformer
	result, err := p.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	expected := append([]byte("aes:"), []byte("encrypted1")...)
	if !bytes.Equal(result, expected) {
		t.Errorf("TransformToStorage returned %q, want %q", result, expected)
	}

	// Verify that only the first transformer was used
	if !bytes.Equal(transformer1.receivedToStorage, []byte("data")) {
		t.Errorf("first transformer received %q, want %q", transformer1.receivedToStorage, []byte("data"))
	}
	if len(transformer2.receivedToStorage) > 0 {
		t.Errorf("second transformer should not be called for write, but received %q", transformer2.receivedToStorage)
	}
	if len(transformer3.receivedToStorage) > 0 {
		t.Errorf("third transformer should not be called for write, but received %q", transformer3.receivedToStorage)
	}
}

