// TestPrefixTransformerFallback verifies fallback behavior when a transformer with a matching prefix fails
func TestPrefixTransformerFallback(t *testing.T) {
	failingTransformer := &mockTransformer{
		decryptErr: fmt.Errorf("decryption failed"),
	}
	workingTransformer := &mockTransformer{
		decryptedData: []byte("recovered"),
	}

	// Note: In the current implementation, if a transformer with a matching prefix fails
	// and it's not an empty prefix, the error is returned without trying other transformers.
	// Empty prefix transformers can fall through on error.
	p := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte{}, Transformer: failingTransformer},
		PrefixTransformer{Prefix: []byte("working:"), Transformer: workingTransformer},
	)

	ctx := context.Background()

	// When data doesn't match the empty prefix pattern, it should try the next transformer
	result, _, err := p.TransformFromStorage(ctx, []byte("working:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	if !bytes.Equal(result, []byte("recovered")) {
		t.Errorf("TransformFromStorage returned %q, want %q", result, []byte("recovered"))
	}
}

