			authCtx := DefaultContext(tt.authenticData)

			// Test encryption
			encrypted, err := transformer.TransformToStorage(ctx, tt.originalData, authCtx)
			if err != nil && !tt.expectError {
				t.Fatalf("TransformToStorage failed: %v", err)
