					Transformer: &mockTransformer{
						encryptErr: fmt.Errorf("encryption failed"),
					},
				},
			},
			data:      []byte("data"),
			operation: "encrypt",
			expectErr: true,
		},
		{
			name: "decryption error with matching prefix",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("aes:"),
					Transformer: &mockTransformer{
						decryptErr: fmt.Errorf("decryption failed"),
					},
				},
			},
			data:      []byte("aes:encrypted"),
			operation: "decrypt",
			expectErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)
			ctx := context.Background()

			if tt.operation == "encrypt" {
				_, err := p.TransformToStorage(ctx, tt.data, nil)
				if !tt.expectErr && err != nil {
					t.Fatalf("TransformToStorage unexpected error: %v", err)
				}
				if tt.expectErr && err == nil {
					t.Fatalf("TransformToStorage should have errored")
				}
			} else if tt.operation == "decrypt" {
				_, _, err := p.TransformFromStorage(ctx, tt.data, nil)
				if !tt.expectErr && err != nil {
					t.Fatalf("TransformFromStorage unexpected error: %v", err)
				}
				if tt.expectErr && err == nil {
					t.Fatalf("TransformFromStorage should have errored")
				}
			}
		})
	}
